import{_ as e,o as l,c as i,an as r}from"./chunks/framework.DKgvuBLA.js";const p=JSON.parse('{"title":"プライバシーポリシー","description":"","frontmatter":{},"headers":[],"relativePath":"ja/privacy-policy.md","filePath":"ja/privacy-policy.md"}'),o={name:"ja/privacy-policy.md"};function t(s,a,h,n,c,d){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="プライバシーポリシー" tabindex="-1">プライバシーポリシー <a class="header-anchor" href="#プライバシーポリシー" aria-label="Permalink to &quot;プライバシーポリシー&quot;">​</a></h1><p>このページでは、<code>particles.js.org</code> が分析および広告サービスに関連する個人データをどのように処理するかについて説明します。</p><h2 id="範囲" tabindex="-1">範囲 <a class="header-anchor" href="#範囲" aria-label="Permalink to &quot;範囲&quot;">​</a></h2><p>このポリシーは、<code>particles.js.org</code> から提供されるドキュメント Web サイトと関連ページを対象としています。</p><h2 id="当社が処理するデータ" tabindex="-1">当社が処理するデータ <a class="header-anchor" href="#当社が処理するデータ" aria-label="Permalink to &quot;当社が処理するデータ&quot;">​</a></h2><ul><li>技術的な閲覧データ (IP 由来のメタデータ、ユーザー エージェント、リファラー、ページ URL)。</li><li>ドキュメントの使用傾向に関する分析イベント。</li><li>同意が与えられた場合に Google AdSense によって要求される広告関連のイベント。</li></ul><h2 id="使用されるサービス" tabindex="-1">使用されるサービス <a class="header-anchor" href="#使用されるサービス" aria-label="Permalink to &quot;使用されるサービス&quot;">​</a></h2><ul><li><strong>Google Analytics 4</strong> によるトラフィックと使用状況の分析。</li><li><strong>Google AdSense</strong> による広告配信とキャンペーンの測定。</li></ul><h2 id="法的根拠と同意" tabindex="-1">法的根拠と同意 <a class="header-anchor" href="#法的根拠と同意" aria-label="Permalink to &quot;法的根拠と同意&quot;">​</a></h2><ul><li>必須の技術ストレージはサイト運営に使用されます。</li><li>分析および広告テクノロジーは、Cookie バナーを介して明示的に同意した場合にのみ有効になります。</li><li>同意を拒否してドキュメントの使用を続けることができます。</li></ul><h2 id="同意ストレージ" tabindex="-1">同意ストレージ <a class="header-anchor" href="#同意ストレージ" aria-label="Permalink to &quot;同意ストレージ&quot;">​</a></h2><ul><li>同意の選択は、サイト固有のキーの下でブラウザー ストレージにローカルに保存されます。</li><li>同意が受け入れられるまで、分析/広告追跡はアクティブ化されません。</li></ul><h2 id="データ共有" tabindex="-1">データ共有 <a class="header-anchor" href="#データ共有" aria-label="Permalink to &quot;データ共有&quot;">​</a></h2><ul><li>データは、Google のサービス規約に従って、サードパーティのプロセッサ/管理者として Google によって処理される場合があります。</li><li>このウェブサイトを通じて個人データを販売することはありません。</li></ul><h2 id="あなたのコントロール" tabindex="-1">あなたのコントロール <a class="header-anchor" href="#あなたのコントロール" aria-label="Permalink to &quot;あなたのコントロール&quot;">​</a></h2><ul><li>Cookie バナーを介して承認または拒否します。</li><li>ブラウザーのサイト データ (ローカル ストレージ/Cookie) をクリアして、選択をリセットします。</li><li>ブラウザのプライバシー制御と広告設定を使用して制限を追加します。</li></ul><h2 id="ポリシーの更新" tabindex="-1">ポリシーの更新 <a class="header-anchor" href="#ポリシーの更新" aria-label="Permalink to &quot;ポリシーの更新&quot;">​</a></h2><p>このポリシーは、追跡機能や法的要件が変更された場合に更新される場合があります。</p><h2 id="連絡先" tabindex="-1">連絡先 <a class="header-anchor" href="#連絡先" aria-label="Permalink to &quot;連絡先&quot;">​</a></h2><p>プライバシーのリクエストについては、プロジェクト リポジトリのサポート チャネルと連絡先チャネルを使用してください。 <a href="https://github.com/tsparticles/tsparticles" target="_blank" rel="noreferrer">https://github.com/tsparticles/tsparticles</a></p>',20)])])}const b=e(o,[["render",t]]);export{p as __pageData,b as default};
